    // Update UI
  }

  static Future<void> handlePaymentFailure(String error) async {
    // Log error
    // Show user error message
    // Retry logic if needed
  }
}

class PaymentWidget extends StatelessWidget {
  final double amount;
  final String currency;
  final Function(bool success) onPaymentComplete;

  const PaymentWidget({
    Key? key,
    required this.amount,
    required this.currency,
    required this.onPaymentComplete,
  }) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        Text('Amount: \$${amount.toStringAsFixed(2)}'),
        ElevatedButton(
          onPressed: () async {
            bool success = await PaymentProcessor.processStripePayment(amount, currency);
            onPaymentComplete(success);
          },
          child: Text('Pay with Stripe'),
        ),
        ElevatedButton(
          onPressed: () async {
            bool success = await PaymentProcessor.processGooglePay(amount, currency);
            onPaymentComplete(success);
          },
          child: Text('Pay with Google Pay'),
        ),
      ],
    );
  }
}

class InAppPurchaseWidget extends StatelessWidget {
  final Function(bool success) onPurchaseComplete;

  const InAppPurchaseWidget({Key? key, required this.onPurchaseComplete}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return FutureBuilder<List<PurchaseDetails>>(
      future: PaymentProcessor.getAvailableProducts(),
      builder: (context, snapshot) {
        if (snapshot.connectionState == ConnectionState.waiting) {
          return CircularProgressIndicator();
        }
        
        if (snapshot.hasError) {
          return Text('Error: ${snapshot.error}');
        }
        
        if (!snapshot.hasData || snapshot.data!.isEmpty) {
          return Text('No products available');
        }
        
        return Column(
          children: snapshot.data!.map((product) {
            return ElevatedButton(
              onPressed: () async {
                bool success = await PaymentProcessor.purchaseProduct(product.id);
                onPurchaseComplete(success);
              },
              child: Text(product.title),
            );
          }).toList(),
        );
      },
    );
  }
}